public object FfiConverterTypeDropCore: FfiConverter<DropCore, Pointer> {

    override fun lower(value: DropCore): Pointer {
        return value.uniffiClonePointer()
    }

    override fun lift(value: Pointer): DropCore {
        return DropCore(value)
    }

    override fun read(buf: ByteBuffer): DropCore {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: DropCore) = 8UL

    override fun write(value: DropCore, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}



