sealed class DropException: kotlin.Exception() {
    
    class Database(
        
        val `msg`: kotlin.String
        ) : DropException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    class Crypto(
        
        val `msg`: kotlin.String
        ) : DropException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    class InvalidData(
        
        val `msg`: kotlin.String
        ) : DropException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    class PeerNotFound(
        
        val `deviceId`: kotlin.String
        ) : DropException() {
        override val message
            get() = "deviceId=${ `deviceId` }"
    }
    

    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<DropException> {
        override fun lift(error_buf: RustBuffer.ByValue): DropException = FfiConverterTypeDropError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeDropError : FfiConverterRustBuffer<DropException> {
    override fun read(buf: ByteBuffer): DropException {
        

        return when(buf.getInt()) {
            1 -> DropException.Database(
                FfiConverterString.read(buf),
                )
            2 -> DropException.Crypto(
                FfiConverterString.read(buf),
                )
            3 -> DropException.InvalidData(
                FfiConverterString.read(buf),
                )
            4 -> DropException.PeerNotFound(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: DropException): ULong {
        return when(value) {
            is DropException.Database -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is DropException.Crypto -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is DropException.InvalidData -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is DropException.PeerNotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`deviceId`)
            )
        }
    }

    override fun write(value: DropException, buf: ByteBuffer) {
        when(value) {
            is DropException.Database -> {
                buf.putInt(1)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is DropException.Crypto -> {
                buf.putInt(2)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is DropException.InvalidData -> {
                buf.putInt(3)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is DropException.PeerNotFound -> {
                buf.putInt(4)
                FfiConverterString.write(value.`deviceId`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




/**
 * @suppress
 */
public object FfiConverterOptionalLong: FfiConverterRustBuffer<kotlin.Long?> {
    override fun read(buf: ByteBuffer): kotlin.Long? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterLong.read(buf)
    }

    override fun allocationSize(value: kotlin.Long?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterLong.allocationSize(value)
        }
    }

    override fun write(value: kotlin.Long?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterLong.write(value, buf)
        }
    }
}




